import React, { useEffect, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import Chatbot from "../Chatbot/Chatbot";

export default function DoctorDashboard() {
  const [appointments, setAppointments] = useState([]);
  const [tab, setTab] = useState("all"); // all, pending, approved, rejected
  const [chatOpen, setChatOpen] = useState(false); // Chatbot toggle
  const token = localStorage.getItem("token");

  useEffect(() => {
    if (!token) return;
    fetchAppointments();
  }, []);

  const fetchAppointments = async () => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/appointments/doctor",
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setAppointments(res.data);
    } catch (err) {
      toast.error("Error fetching appointments");
    }
  };

  const handleStatusUpdate = async (id, status) => {
    try {
      await axios.patch(
        `http://localhost:5000/api/appointments/${id}/status`,
        { status },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      toast.success(`Appointment ${status}`);
      fetchAppointments();
    } catch (err) {
      toast.error("Failed to update status");
    }
  };

  const handlePaymentVerification = async (id, action) => {
    try {
      await axios.patch(
        `http://localhost:5000/api/appointments/${id}/verify-payment`,
        { action },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      toast.success(`Payment ${action}`);
      fetchAppointments();
    } catch (err) {
      toast.error("Failed to verify payment");
    }
  };

  // Filter appointments based on selected tab
  const filteredAppointments =
    tab === "all" ? appointments : appointments.filter((a) => a.status === tab);

  return (
    <div className="p-6 bg-gray-100 min-h-screen relative">
      <h1 className="text-3xl font-bold mb-6">Doctor Dashboard</h1>

      {/* Tabs */}
      <div className="flex gap-4 mb-6">
        {["all", "pending", "approved", "rejected"].map((t) => (
          <button
            key={t}
            className={`px-4 py-2 rounded ${
              tab === t ? "bg-blue-600 text-white" : "bg-gray-200 text-gray-700"
            }`}
            onClick={() => setTab(t)}
          >
            {t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      {/* Appointments List */}
      {filteredAppointments.length === 0 && <p>No appointments found.</p>}

      {filteredAppointments.map((app) => (
        <div key={app._id} className="border p-4 mb-3 rounded bg-gray-50">
          <p>
            <strong>Patient:</strong> {app.patient?.name}
          </p>
          <p>
            <strong>Date:</strong> {new Date(app.date).toLocaleDateString()}
          </p>
          <p>
            <strong>Time:</strong> {app.time}
          </p>
          <p>
            <strong>Status:</strong>{" "}
            <span
              className={`font-bold ${
                app.status === "approved"
                  ? "text-green-600"
                  : app.status === "rejected"
                  ? "text-red-600"
                  : "text-yellow-600"
              }`}
            >
              {app.status}
            </span>
          </p>

          <p>
            <strong>Payment Status:</strong>{" "}
            <span
              className={`font-bold ${
                app.paymentStatus === "paid"
                  ? "text-green-600"
                  : app.paymentStatus === "rejected"
                  ? "text-red-600"
                  : app.paymentStatus === "pending_verification"
                  ? "text-blue-600"
                  : "text-gray-600"
              }`}
            >
              {app.paymentStatus || "unpaid"}
            </span>
          </p>

          {/* Payment Details for verification */}
          {app.paymentStatus === "pending_verification" && (
            <div className="mt-2 p-2 bg-gray-100 rounded">
              <p>
                <strong>Payment Method:</strong> {app.paymentMethod}
              </p>
              {app.paymentScreenshot && (
                <p>
                  <strong>Screenshot:</strong>{" "}
                  <a
                    href={`http://localhost:5000/${app.paymentScreenshot}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 underline"
                  >
                    View
                  </a>
                </p>
              )}

              <div className="flex gap-2 mt-2">
                <button
                  className="bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700"
                  onClick={() => handlePaymentVerification(app._id, "accept")}
                >
                  Approve Payment
                </button>
                <button
                  className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-700"
                  onClick={() => handlePaymentVerification(app._id, "reject")}
                >
                  Reject Payment
                </button>
              </div>
            </div>
          )}

          {/* Approve / Reject Appointment */}
          {app.status === "pending" && (
            <div className="flex gap-2 mt-2">
              <button
                className="bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700"
                onClick={() => handleStatusUpdate(app._id, "approved")}
              >
                Approve Appointment
              </button>
              <button
                className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-700"
                onClick={() => handleStatusUpdate(app._id, "rejected")}
              >
                Reject Appointment
              </button>
            </div>
          )}
        </div>
      ))}

      {/* Chatbot toggle */}
      <div className="fixed bottom-5 right-5 z-50">
        {!chatOpen && (
          <button
            onClick={() => setChatOpen(true)}
            className="bg-blue-600 p-3 rounded-full text-white shadow-lg hover:bg-blue-700 transition"
          >
            💬
          </button>
        )}
        {chatOpen && <Chatbot />}
      </div>
    </div>
  );
}
